const fs = require('fs');
const vm = require('vm');
const ts = require('typescript');
const source = fs.readFileSync('supabase/functions/ai-generate-effect/templates.ts', 'utf8');
const { outputText } = ts.transpileModule(source, {
  compilerOptions: {
    module: ts.ModuleKind.CommonJS,
    target: ts.ScriptTarget.ES2020,
  },
});
const module = { exports: {} };
vm.runInNewContext(outputText, {
  module,
  exports: module.exports,
  require,
  console,
});
const { extractQuestionResponse, extractEffectCodeAndMeta } = module.exports;
const question = extractQuestionResponse('// QUESTION_RESPONSE\nHello there');
const effect = extractEffectCodeAndMeta('// NAME: Test\n// DESCRIPTION: Demo\n// PARAMS: []\n// MESSAGE: Built a subtle pulse\nfunction Demo() { return React.createElement(React.Fragment, null); }\nexports.default = Demo');
let validationError = null;
try {
  extractEffectCodeAndMeta('// NAME: Broken\n// DESCRIPTION: Demo\n// PARAMS: []\n// MESSAGE: Still invalid\nfunction Demo() { return React.createElement(React.Fragment, null); }');
} catch (error) {
  validationError = error instanceof Error ? error.message : String(error);
}
console.log(JSON.stringify({
  question,
  effectMessage: effect.message,
  effectCodeHasMessageMarker: effect.code.includes('MESSAGE'),
  validationError,
}, null, 2));
